import { Bookmark, NotionDatabase } from "../types";

const NOTION_API_BASE = "https://api.notion.com/v1";
const NOTION_VERSION = "2022-06-28";

export class NotionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'NotionError';
  }
}

// Helper to handle fetch with Proxy and Headers
async function notionFetch(endpoint: string, method: string, token: string, proxyUrl: string, body?: any) {
  const targetUrl = `${NOTION_API_BASE}${endpoint}`;
  // If a proxy is provided, prepend it. If proxyUrl is empty string, fetch directly.
  const fetchUrl = proxyUrl ? `${proxyUrl}${encodeURIComponent(targetUrl)}` : targetUrl;

  const headers: Record<string, string> = {
    "Authorization": `Bearer ${token}`,
    "Notion-Version": NOTION_VERSION,
    "Content-Type": "application/json",
  };

  const response = await fetch(fetchUrl, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });

  if (!response.ok) {
    let errorMsg = `Notion API Error: ${response.status}`;
    try {
      const errData = await response.json();
      errorMsg = errData.message || errorMsg;
    } catch (e) {
      // ignore json parse error
    }
    throw new NotionError(errorMsg);
  }

  return response.json();
}

export async function getAccessibleDatabases(token: string, proxyUrl: string): Promise<NotionDatabase[]> {
  try {
    // Search for databases
    const data = await notionFetch("/search", "POST", token, proxyUrl, {
      filter: {
        value: "database",
        property: "object",
      },
      page_size: 100,
    });

    return data.results.map((db: any) => ({
      id: db.id,
      title: db.title?.[0]?.plain_text || "Untitled Database",
      url: db.url,
      properties: db.properties,
    }));
  } catch (error) {
    console.error("Failed to fetch Notion databases", error);
    throw error;
  }
}

// Heuristic to find suitable properties in the database to map our data to
function findPropertyId(properties: Record<string, any>, possibleNames: string[], type: string): string | null {
  // 1. Exact match on name and type
  for (const name of possibleNames) {
    const prop = properties[name]; // Notion keys properties by name (mostly)
    if (prop && prop.type === type) return name;

    // Sometimes keys are IDs, we iterate values
    const foundEntry = Object.entries(properties).find(([key, val]) => key.toLowerCase() === name.toLowerCase() && val.type === type);
    if (foundEntry) return foundEntry[0];
  }

  // 2. Loose match on type only (fallback) - risky for text, good for URL/Date
  if (type === 'url' || type === 'date') {
    const found = Object.entries(properties).find(([_, val]) => val.type === type);
    if (found) return found[0];
  }

  return null;
}

export async function exportToNotion(
  token: string, 
  proxyUrl: string,
  databaseId: string, 
  databaseProperties: Record<string, any>, 
  bookmarks: Bookmark[]
): Promise<{ success: number; failed: number }> {

  // Identify Target Properties
  const propMap = {
    title: Object.keys(databaseProperties).find(k => databaseProperties[k].type === 'title') || 'Name',
    url: findPropertyId(databaseProperties, ['URL', 'Link', 'Website', 'Address'], 'url'),
    summary: findPropertyId(databaseProperties, ['Summary', 'Description', 'Notes', 'AI Summary'], 'rich_text'),
    keywords: findPropertyId(databaseProperties, ['Keywords', 'Tags', 'Topics', 'Categories'], 'multi_select'),
    date: findPropertyId(databaseProperties, ['Date', 'Created', 'Added', 'Publication Date'], 'date'),
  };

  let success = 0;
  let failed = 0;

  for (const bookmark of bookmarks) {
    try {
      const properties: any = {};

      // 1. Title (Mandatory)
      properties[propMap.title] = {
        title: [
          { text: { content: bookmark.title || "Untitled" } }
        ]
      };

      // 2. URL
      if (propMap.url) {
        properties[propMap.url] = { url: bookmark.url };
      }

      // 3. Summary (Rich Text)
      if (propMap.summary) {
        // Notion allows max 2000 chars per text block, truncate if needed
        const summaryText = (bookmark.summary || "").substring(0, 2000);
        properties[propMap.summary] = {
          rich_text: [
            { text: { content: summaryText } }
          ]
        };
      }

      // 4. Keywords (Multi-select)
      if (propMap.keywords && bookmark.keywords.length > 0) {
        properties[propMap.keywords] = {
          multi_select: bookmark.keywords.map(k => ({ name: k.replace(/,/g, '') })) // commas not allowed in options
        };
      }

      // 5. Date
      if (propMap.date) {
        const dateVal = bookmark.createdAt ? new Date(bookmark.createdAt).toISOString() : new Date().toISOString();
        properties[propMap.date] = {
          date: { start: dateVal }
        };
      }

      // 6. Content Body (If we have sources or detailed summary, append to body)
      const children = [];
      if (bookmark.summary) {
         children.push({
            object: 'block',
            type: 'paragraph',
            paragraph: {
                rich_text: [{ type: 'text', text: { content: bookmark.summary } }]
            }
         });
      }

      if (bookmark.sources && bookmark.sources.length > 0) {
          children.push({
            object: 'block',
            type: 'heading_3',
            heading_3: { rich_text: [{ type: 'text', text: { content: 'Sources' } }] }
          });
          bookmark.sources.forEach(source => {
              children.push({
                  object: 'block',
                  type: 'bulleted_list_item',
                  bulleted_list_item: {
                      rich_text: [
                          { type: 'text', text: { content: source.title || source.uri, link: { url: source.uri } } }
                      ]
                  }
              });
          });
      }

      await notionFetch("/pages", "POST", token, proxyUrl, {
        parent: { database_id: databaseId },
        properties: properties,
        children: children.length > 0 ? children : undefined
      });

      success++;
    } catch (e) {
      console.error(`Failed to export bookmark ${bookmark.url} to Notion`, e);
      failed++;
    }
  }

  return { success, failed };
}

