import { Bookmark, NotionDatabase } from "../types";

const NOTION_API_BASE = "https://api.notion.com/v1";
const NOTION_VERSION = "2022-06-28";

export class NotionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'NotionError';
  }
}

// Helper to handle fetch with Proxy and Headers
async function notionFetch(endpoint: string, method: string, token: string, proxyUrl: string, body?: any) {
  const targetUrl = `${NOTION_API_BASE}${endpoint}`;
  // If a proxy is provided, prepend it. If proxyUrl is empty string, fetch directly.
  const fetchUrl = proxyUrl ? `${proxyUrl}${encodeURIComponent(targetUrl)}` : targetUrl;

  const headers: Record<string, string> = {
    "Authorization": `Bearer ${token}`,
    "Notion-Version": NOTION_VERSION,
    "Content-Type": "application/json",
  };

  const response = await fetch(fetchUrl, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });

  if (!response.ok) {
    let errorMsg = `Notion API Error: ${response.status}`;
    try {
      const errData = await response.json();
      errorMsg = errData.message || errorMsg;
    } catch (e) {
      // ignore json parse error
    }
    throw new NotionError(errorMsg);
  }

  return response.json();
}

export async function getAccessibleDatabases(token: string, proxyUrl: string): Promise<NotionDatabase[]> {
  try {
    // Search for databases
    const data = await notionFetch("/search", "POST", token, proxyUrl, {
      filter: {
        value: "database",
        property: "object",
      },
      page_size: 100,
    });

    return data.results.map((db: any) => ({
      id: db.id,
      title: db.title?.[0]?.plain_text || "Untitled Database",
      url: db.url,
      properties: db.properties,
    }));
  } catch (error) {
    console.error("Failed to fetch Notion databases", error);
    throw error;
  }
}

async function ensureDatabaseSchema(token: string, proxyUrl: string, databaseId: string, currentProperties: Record<string, any>) {
    const propertiesToUpdate: Record<string, any> = {};

    // Helper to check if a property exists with specific name and type
    const hasProperty = (name: string, type: string) => {
        return Object.values(currentProperties).some((p: any) => p.name === name && p.type === type);
    };

    // 1. URL (Type: url) -> "URL"
    if (!hasProperty('URL', 'url')) {
        propertiesToUpdate['URL'] = { url: {} };
    }

    // 2. Summary (Type: rich_text) -> "Description"
    if (!hasProperty('Description', 'rich_text')) {
        propertiesToUpdate['Description'] = { rich_text: {} };
    }

    // 3. Keywords (Type: multi_select) -> "Keywords"
    if (!hasProperty('Keywords', 'multi_select')) {
        propertiesToUpdate['Keywords'] = { multi_select: {} };
    }

    // 4. CreatedAt (Type: date) -> "Date"
    if (!hasProperty('Date', 'date')) {
        propertiesToUpdate['Date'] = { date: {} };
    }

    if (Object.keys(propertiesToUpdate).length > 0) {
        await notionFetch(`/databases/${databaseId}`, "PATCH", token, proxyUrl, {
            properties: propertiesToUpdate
        });
    }
}

export async function exportToNotion(
  token: string, 
  proxyUrl: string,
  databaseId: string, 
  databaseProperties: Record<string, any>, 
  bookmarks: Bookmark[]
): Promise<{ success: number; failed: number }> {

  // 1. Ensure the database has the required schema columns
  try {
      await ensureDatabaseSchema(token, proxyUrl, databaseId, databaseProperties);
  } catch (e) {
      console.warn("Failed to update database schema, attempting to proceed with existing properties...", e);
  }

  // 2. Map properties. We prioritize the standard names we expect/enforced.
  // Note: Notion properties are keyed by their ID usually in API responses, but we need Names for creation? 
  // Actually, for creating pages, we can use property Names or IDs. Using Names is safer if we just created them.

  // Find the Title property (always exists)
  const titlePropKey = Object.keys(databaseProperties).find(k => databaseProperties[k].type === 'title');
  const titlePropName = titlePropKey ? databaseProperties[titlePropKey].name : 'Name';

  let success = 0;
  let failed = 0;

  for (const bookmark of bookmarks) {
    try {
      const properties: any = {};

      // Title
      properties[titlePropName] = {
        title: [
          { text: { content: bookmark.title || "Untitled" } }
        ]
      };

      // URL
      properties['URL'] = { url: bookmark.url };

      // Description
      const summaryText = (bookmark.summary || "").substring(0, 2000);
      properties['Description'] = {
        rich_text: [
          { text: { content: summaryText } }
        ]
      };

      // Keywords
      if (bookmark.keywords.length > 0) {
        properties['Keywords'] = {
          multi_select: bookmark.keywords.map(k => ({ name: k.replace(/,/g, '') }))
        };
      }

      // Date
      const dateVal = bookmark.createdAt ? new Date(bookmark.createdAt).toISOString() : new Date().toISOString();
      properties['Date'] = {
        date: { start: dateVal }
      };

      // Content Body (Sources)
      const children = [];
      // We put the summary in the property 'Description', but also optionally in body? 
      // User asked for summary as 'Description' property. Let's keep body for Sources only.

      if (bookmark.sources && bookmark.sources.length > 0) {
          children.push({
            object: 'block',
            type: 'heading_3',
            heading_3: { rich_text: [{ type: 'text', text: { content: 'Sources' } }] }
          });
          bookmark.sources.forEach(source => {
              children.push({
                  object: 'block',
                  type: 'bulleted_list_item',
                  bulleted_list_item: {
                      rich_text: [
                          { type: 'text', text: { content: source.title || source.uri, link: { url: source.uri } } }
                      ]
                  }
              });
          });
      }

      await notionFetch("/pages", "POST", token, proxyUrl, {
        parent: { database_id: databaseId },
        properties: properties,
        children: children.length > 0 ? children : undefined
      });

      success++;
    } catch (e) {
      console.error(`Failed to export bookmark ${bookmark.url} to Notion`, e);
      failed++;
    }
  }

  return { success, failed };
}

import React, { useEffect, useState } from 'react';
import { Bookmark, NotionDatabase } from '../types';
import { getAccessibleDatabases, exportToNotion } from '../services/notionService';
import { Spinner } from './common/Spinner';
import { CloseIcon } from './common/Icons';

interface NotionSyncModalProps {
  isOpen: boolean;
  onClose: () => void;
  bookmarks: Bookmark[];
  notionConfig: { apiKey: string; proxyUrl: string };
  onOpenSettings: () => void;
}

export const NotionSyncModal: React.FC<NotionSyncModalProps> = ({ 
  isOpen, 
  onClose, 
  bookmarks, 
  notionConfig,
  onOpenSettings
}) => {
  const [step, setStep] = useState<'loading' | 'select' | 'syncing' | 'complete' | 'error'>('loading');
  const [databases, setDatabases] = useState<NotionDatabase[]>([]);
  const [selectedDbId, setSelectedDbId] = useState<string>('');
  const [errorMsg, setErrorMsg] = useState<string>('');
  const [syncStats, setSyncStats] = useState({ success: 0, failed: 0 });

  useEffect(() => {
    if (isOpen) {
      if (!notionConfig.apiKey) {
          setErrorMsg("No API Key configured");
          setStep('error');
          return;
      }
      fetchDatabases();
    } else {
        // Reset state on close
        setStep('loading');
        setDatabases([]);
        setSelectedDbId('');
        setErrorMsg('');
    }
  }, [isOpen, notionConfig.apiKey]);

  const fetchDatabases = async () => {
    setStep('loading');
    setErrorMsg('');
    try {
      const dbs = await getAccessibleDatabases(notionConfig.apiKey, notionConfig.proxyUrl);
      if (dbs.length === 0) {
        setErrorMsg("No databases found. Make sure you have connected your Integration to a Database (via the '...' menu > Connections on the database page).");
        setStep('error');
      } else {
        setDatabases(dbs);
        setStep('select');
        // Auto select first if available
        if (dbs.length > 0) setSelectedDbId(dbs[0].id);
      }
    } catch (e: any) {
      setErrorMsg(e.message || "Failed to fetch databases. Check your API Key and Proxy settings.");
      setStep('error');
    }
  };

  const handleSync = async () => {
    if (!selectedDbId) return;
    const db = databases.find(d => d.id === selectedDbId);
    if (!db) return;

    setStep('syncing');
    try {
      const results = await exportToNotion(
        notionConfig.apiKey, 
        notionConfig.proxyUrl,
        selectedDbId, 
        db.properties, 
        bookmarks
      );
      setSyncStats(results);
      setStep('complete');
    } catch (e: any) {
      setErrorMsg(e.message || "Sync failed.");
      setStep('error');
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-md p-6 animate-fade-in">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800 dark:text-slate-100">
             Export to Notion
          </h2>
          <button 
            onClick={onClose} 
            className="p-2 text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 transition-colors"
          >
            <CloseIcon className="h-6 w-6" />
          </button>
        </div>

        {step === 'error' && (
            <div className="text-center">
                <div className="text-red-500 bg-red-100 dark:bg-red-900/50 p-4 rounded-lg mb-4 text-sm">
                    {errorMsg}
                </div>
                 {errorMsg.includes("API Key") ? (
                     <button onClick={onOpenSettings} className="text-blue-600 hover:underline text-sm">Open Settings</button>
                 ) : (
                     <button onClick={fetchDatabases} className="px-4 py-2 bg-slate-200 dark:bg-slate-700 rounded-md text-sm">Try Again</button>
                 )}
            </div>
        )}

        {step === 'loading' && (
            <div className="flex flex-col items-center justify-center py-8">
                <Spinner className="w-8 h-8 text-blue-500 mb-4" />
                <p className="text-slate-600 dark:text-slate-300">Fetching databases...</p>
            </div>
        )}

        {step === 'select' && (
            <div>
                <p className="text-sm text-slate-600 dark:text-slate-300 mb-4">
                    Select a database to merge <strong>{bookmarks.length}</strong> bookmarks into.
                </p>
                <div className="bg-blue-50 dark:bg-blue-900/30 p-3 rounded-lg mb-4 border border-blue-100 dark:border-blue-800">
                    <p className="text-xs text-blue-800 dark:text-blue-200">
                        <strong>Note:</strong> We will check for columns named <code>URL</code>, <code>Description</code>, <code>Keywords</code>, and <code>Date</code>. If they don't exist, we will create them automatically.
                    </p>
                </div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Target Database</label>
                <select 
                    value={selectedDbId} 
                    onChange={(e) => setSelectedDbId(e.target.value)}
                    className="w-full p-2.5 bg-slate-50 dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none mb-6 dark:text-white"
                >
                    {databases.map(db => (
                        <option key={db.id} value={db.id}>{db.title}</option>
                    ))}
                </select>
                <div className="flex justify-end space-x-3">
                    <button onClick={onClose} className="px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancel</button>
                    <button onClick={handleSync} className="px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-sm">
                        Start Sync
                    </button>
                </div>
            </div>
        )}

        {step === 'syncing' && (
            <div className="flex flex-col items-center justify-center py-8">
                <Spinner className="w-8 h-8 text-blue-500 mb-4" />
                <p className="text-slate-600 dark:text-slate-300">Syncing bookmarks to Notion...</p>
                <p className="text-xs text-slate-500 mt-2">Updating schema and adding pages...</p>
            </div>
        )}

        {step === 'complete' && (
            <div className="text-center py-4">
                <div className="mx-auto flex items-center justify-center h-12 w-12 rounded-full bg-green-100 dark:bg-green-900 mb-4">
                    <svg className="h-6 w-6 text-green-600 dark:text-green-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                </div>
                <h3 className="text-lg font-medium text-slate-900 dark:text-white mb-2">Sync Complete!</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">
                    Successfully added {syncStats.success} bookmarks.<br/>
                    {syncStats.failed > 0 && <span className="text-red-500">Failed to add {syncStats.failed} bookmarks.</span>}
                </p>
                <button onClick={onClose} className="w-full px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg shadow-sm">
                    Done
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Custom error to be thrown when API key is invalid
export class ApiKeyError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ApiKeyError';
  }
}

const MAX_RETRIES = 2; 
const INITIAL_BACKOFF_MS = 2500;

function delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

export interface BookmarkResult {
    url: string;
    title: string; 
    summary: string; 
    keywords: string[]; 
    publicationDate: string | null; 
    sources: { uri: string; title: string }[] 
}

// Helper to fetch tweet content via API or oEmbed
async function fetchTweetContext(url: string, apiKey?: string): Promise<string | null> {
    const tweetIdMatch = url.match(/(?:twitter\.com|x\.com)\/(?:#!\/)?(\w+)\/status\/(\d+)/);
    if (!tweetIdMatch) return null;
    const tweetId = tweetIdMatch[2];

    // Try API if key is present
    if (apiKey) {
        try {
            // Note: This often fails in browser due to CORS unless proxy/extension is used
            const res = await fetch(`https://api.twitter.com/2/tweets/${tweetId}?tweet.fields=text,created_at,author_id`, {
                headers: {
                    'Authorization': `Bearer ${apiKey}`
                }
            });
            if (res.ok) {
                const data = await res.json();
                return `Tweet content: "${data.data.text}" (Posted: ${data.data.created_at})`;
            } else {
                console.warn(`Twitter API returned status ${res.status}, falling back.`);
            }
        } catch (e) {
            console.warn("Twitter API fetch failed (likely CORS), falling back to oEmbed", e);
        }
    }

    // Fallback to oEmbed (Robust for public tweets)
    try {
        const oembedUrl = `https://publish.twitter.com/oembed?url=${encodeURIComponent(url)}`;
        const res = await fetch(oembedUrl);
        if (res.ok) {
            const data = await res.json();
            // Clean up HTML tags from the blockquote to get raw text
            if (data.html) {
                const tempDiv = document.createElement('div');
                tempDiv.innerHTML = data.html;
                const text = tempDiv.textContent || tempDiv.innerText || "";
                return `Tweet content (via oEmbed): "${text.replace(/\n+/g, ' ').trim()}"`;
            }
        }
    } catch (e) {
        console.warn("Twitter oEmbed failed", e);
    }

    return null;
}

// Helper to fetch youtube content details via proxy
async function fetchYouTubeContext(url: string, proxyUrl?: string): Promise<string | null> {
    const regExp = /^.*((youtu.be\/)|(v\/)|(\/u\/\w\/)|(embed\/)|(watch\?))\??v?=?([^#&?]*).*/;
    const match = url.match(regExp);
    const videoId = (match && match[7].length === 11) ? match[7] : false;

    if (!videoId) return null;

    // Use proxy if available to fetch the page HTML and extract meta description
    if (proxyUrl) {
        const targetUrl = `https://www.youtube.com/watch?v=${videoId}`;
        const fetchUrl = `${proxyUrl}${encodeURIComponent(targetUrl)}`;
        try {
            const res = await fetch(fetchUrl);
            if (res.ok) {
                const html = await res.text();
                const descMatch = html.match(/<meta name="description" content="([^"]*)"/);
                const titleMatch = html.match(/<meta name="title" content="([^"]*)"/);

                const title = titleMatch ? titleMatch[1] : '';
                const desc = descMatch ? descMatch[1] : '';

                if (title || desc) {
                     return `YouTube Video Details:\nTitle: ${title}\nDescription: ${desc}`;
                }
            }
        } catch (e) {
            console.warn("YouTube proxy fetch failed, relying on Google Search tool", e);
        }
    }
    return null;
}

/**
 * Generates details for a batch of URLs in a single API call to optimize quota usage.
 * Processes multiple URLs simultaneously to stay within RPM/RPD limits.
 */
export async function generateBookmarksBatch(urls: string[], xApiKey?: string, proxyUrl?: string): Promise<BookmarkResult[]> {
    if (!process.env.API_KEY) {
        throw new ApiKeyError("API_KEY environment variable is not set.");
    }

    if (urls.length === 0) return [];

    // Pre-fetch contexts for X/Twitter and YouTube URLs
    const contexts = await Promise.all(urls.map(async (url) => {
        if (url.includes('twitter.com') || url.includes('x.com')) {
            return await fetchTweetContext(url, xApiKey);
        }
        if (url.includes('youtube.com') || url.includes('youtu.be')) {
            return await fetchYouTubeContext(url, proxyUrl);
        }
        return null;
    }));

    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const prompt = `
            Analyze the following list of URLs and provide detailed summaries:
            ${urls.map((url, i) => {
                const ctx = contexts[i];
                return `${i + 1}. ${url}${ctx ? `\n   [Additional Context Retrieved]: ${ctx}` : ''}`;
            }).join('\n')}

            Instructions for EACH URL:
            1. Use the search tool to find the actual page content and metadata. 
               - IF Additional Context is provided above for a URL (e.g. Tweet content, YouTube description), PRIORTIZE using that context for the summary.
               - For YouTube videos, specifically read the VIDEO DESCRIPTION and use it to generate the summary.
            2. Extract a clear title and a 2-sentence informative summary.
            3. Identify 3-5 specific keywords.
            4. SEARCH FOR THE ORIGINAL PUBLICATION DATE. If the page is an article, news piece, blog post, or video, find when it was originally published.
            5. Return the publication date strictly in ISO 8601 format (YYYY-MM-DD). If no clear publication date is found, return null.

            Format your response as a valid JSON array of objects.
            JSON structure:
            [
              {
                "url": "input_url_here",
                "title": "Page Title",
                "summary": "Informative summary...",
                "keywords": ["kw1", "kw2"],
                "publicationDate": "YYYY-MM-DD"
              }
            ]
            `;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    tools: [{ googleSearch: {} }],
                    temperature: 0.2,
                    responseMimeType: "application/json"
                }
            });

            const responseText = response.text;
            if (!responseText) {
                const candidate = response.candidates?.[0];
                if (candidate?.finishReason === 'SAFETY') throw new Error("Batch blocked by safety filters.");
                throw new Error("Empty AI response received.");
            }

            // Extract global grounding sources for this batch
            const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
            const groundingChunks = groundingMetadata?.groundingChunks || [];
            const sources = groundingChunks
                .filter((chunk: any) => chunk.web && chunk.web.uri)
                .map((chunk: any) => ({
                    uri: chunk.web.uri,
                    title: chunk.web.title || chunk.web.uri,
                }));

            let results: any[];
            try {
                results = JSON.parse(responseText.trim());
                if (!Array.isArray(results)) throw new Error("Response is not a JSON array.");
            } catch (e) {
                console.error("Failed to parse batch JSON:", responseText);
                throw new Error("Invalid JSON format in AI response.");
            }

            // Map and validate results against requested URLs
            return urls.map(originalUrl => {
                const found = results.find(r => 
                    r.url?.toLowerCase() === originalUrl.toLowerCase() || 
                    originalUrl.toLowerCase().includes(r.url?.toLowerCase() || '---')
                );

                // Validate publicationDate format
                let validDate: string | null = null;
                if (found?.publicationDate && typeof found.publicationDate === 'string') {
                    const d = new Date(found.publicationDate);
                    if (!isNaN(d.getTime()) && d.getFullYear() > 1970) {
                        validDate = d.toISOString();
                    }
                }

                return {
                    url: originalUrl,
                    title: found?.title || originalUrl.split('/')[2] || "Untitled",
                    summary: found?.summary || "Summary could not be generated.",
                    keywords: Array.isArray(found?.keywords) ? found.keywords : [],
                    publicationDate: validDate,
                    sources: sources.slice(0, 5), // Provide representative sources for the batch
                };
            });

        } catch (error: any) {
            console.error(`Batch Attempt ${attempt + 1} failed:`, error);
            const status = error?.status;
            const message = error?.message || "";

            if (message.includes('API key not valid') || message.includes('404')) {
                throw new ApiKeyError("API Key invalid or expired.");
            }

            // Handle Rate Limiting (429) specifically with exponential backoff
            if ((status === 429 || message.includes('RESOURCE_EXHAUSTED')) && attempt < MAX_RETRIES) {
                const waitTime = INITIAL_BACKOFF_MS * Math.pow(2.5, attempt);
                await delay(waitTime);
                continue;
            }

            if (attempt === MAX_RETRIES) throw error;
            await delay(1500);
        }
    }
    throw new Error("Batch processing failed.");
}

export async function generateBookmarkDetails(url: string, xApiKey?: string, proxyUrl?: string): Promise<BookmarkResult> {
    const results = await generateBookmarksBatch([url], xApiKey, proxyUrl);
    return results[0];
}

import React, { useState, useCallback, useEffect } from 'react';
import { UrlInput } from './components/UrlInput';
import { BookmarkList } from './components/BookmarkList';
import { Header } from './components/Header';
import { SettingsModal } from './components/SettingsModal';
import { NotionSyncModal } from './components/NotionSyncModal';
import { generateBookmarksBatch, ApiKeyError } from './services/geminiService';
import { Bookmark } from './types';
