        }

        // Fallback for Netscape bookmark format without ADD_DATE
        const hrefMatch = trimmedLine.match(/<a\s+href="([^"]+)"/i);
        if (hrefMatch && hrefMatch[1]) {
            return { url: hrefMatch[1], addDate: undefined };
