const AI_BOOKMARKS_STORAGE_KEY = 'ai-bookmark-manager-bookmarks';
const THEME_STORAGE_KEY = 'ai-bookmark-manager-theme';
const X_API_KEY_STORAGE_KEY = 'ai-bookmark-manager-x-api-key';
